SELECT COUNT(*), COUNT(DISTINCT UserID), COUNT(DISTINCT URL) FROM hits WHERE Title LIKE '%news%' OR Title LIKE '%sport%' OR Title LIKE '%video%';
SELECT COUNT(*) FROM hits WHERE URL LIKE '%http%' AND Title NOT LIKE '%error%';
SELECT COUNT(DISTINCT UserID) FROM hits WHERE IsMobile = 1;
SELECT COUNT(DISTINCT URL) FROM hits;
SELECT COUNT(DISTINCT WatchID) FROM hits WHERE IsRefresh = 0;
SELECT COUNT(DISTINCT Title) FROM hits WHERE Title <> '';
SELECT COUNT(DISTINCT Referer) FROM hits WHERE Referer <> '';
SELECT COUNT(DISTINCT URL), COUNT(DISTINCT Title), COUNT(DISTINCT SearchPhrase) FROM hits;
SELECT BrowserCountry, MIN(LENGTH(URL)), MAX(LENGTH(URL)), AVG(LENGTH(URL)), COUNT(DISTINCT URL) FROM hits WHERE URL <> '' GROUP BY BrowserCountry ORDER BY 5 DESC LIMIT 25;
SELECT BrowserCountry, SUM(LENGTH(Title)), SUM(LENGTH(URL)), SUM(LENGTH(Referer)) FROM hits WHERE BrowserCountry <> '' GROUP BY BrowserCountry ORDER BY 2 DESC LIMIT 25;
SELECT BrowserCountry, COUNT(*), COUNT(DISTINCT UserID) FROM hits WHERE BrowserCountry <> '' GROUP BY BrowserCountry ORDER BY 2 DESC LIMIT 25;
SELECT BrowserLanguage, COUNT(*), COUNT(DISTINCT UserID) FROM hits WHERE BrowserLanguage <> '' GROUP BY BrowserLanguage ORDER BY 2 DESC LIMIT 25;
SELECT ClientTimeZone, COUNT(*), AVG(ResolutionWidth), COUNT(DISTINCT UserID) FROM hits GROUP BY ClientTimeZone ORDER BY 2 DESC LIMIT 25;
SELECT URLCategoryID, COUNT(*), COUNT(DISTINCT URL) FROM hits WHERE URLCategoryID <> 0 GROUP BY URLCategoryID ORDER BY 2 DESC LIMIT 25;
SELECT RefererCategoryID, RefererRegionID, COUNT(*), COUNT(DISTINCT UserID) FROM hits WHERE RefererCategoryID <> 0 GROUP BY RefererCategoryID, RefererRegionID ORDER BY 3 DESC LIMIT 25;
SELECT Age, Sex, Income, COUNT(*), COUNT(DISTINCT UserID), COUNT(DISTINCT URL) FROM hits WHERE Age > 0 GROUP BY Age, Sex, Income ORDER BY 4 DESC LIMIT 25;
SELECT EventDate, COUNT(*), COUNT(DISTINCT UserID) FROM hits GROUP BY EventDate ORDER BY EventDate;
SELECT EXTRACT(HOUR FROM EventTime) AS h, COUNT(*), COUNT(DISTINCT UserID) FROM hits GROUP BY h ORDER BY h;
SELECT DATE_TRUNC('hour', EventTime) AS h, COUNT(*), COUNT(DISTINCT UserID) FROM hits GROUP BY h ORDER BY h LIMIT 100;
SELECT EXTRACT(DOW FROM EventTime) AS d, COUNT(*), COUNT(DISTINCT UserID), COUNT(DISTINCT URL) FROM hits GROUP BY d ORDER BY d;
SELECT EventDate, AVG(SendTiming), AVG(DNSTiming), AVG(ConnectTiming), AVG(ResponseEndTiming), COUNT(DISTINCT UserID) FROM hits WHERE SendTiming > 0 GROUP BY EventDate ORDER BY EventDate;
SELECT EXTRACT(MONTH FROM EventDate) AS m, COUNT(*), COUNT(DISTINCT UserID) FROM hits GROUP BY m ORDER BY m;
SELECT EventDate, SUM(IsMobile) AS m, SUM(1 - IsMobile) AS d, SUM(IsRefresh) AS r, COUNT(DISTINCT UserID) AS u FROM hits GROUP BY EventDate ORDER BY EventDate;
SELECT COUNT(*) FROM hits WHERE LOWER(Title) LIKE '%games%';
SELECT COUNT(*) FROM hits WHERE Referer LIKE 'http://%' AND Referer NOT LIKE '%google%';
SELECT REGEXP_REPLACE(URL, '^https?://([^/]+).*', '\1') AS host, COUNT(*) AS c FROM hits WHERE URL <> '' GROUP BY host ORDER BY c DESC LIMIT 25;
SELECT REGEXP_REPLACE(Referer, '^https?://(?:www\.)?([^/]+)/.*$', '\1') AS host, COUNT(DISTINCT UserID) AS u FROM hits WHERE Referer <> '' GROUP BY host HAVING COUNT(*) > 1000 ORDER BY u DESC LIMIT 25;
SELECT SUBSTRING(URL, 1, 30) AS prefix, COUNT(*), COUNT(DISTINCT UserID) FROM hits WHERE URL <> '' GROUP BY prefix ORDER BY 2 DESC LIMIT 25;
SELECT BrowserCountry, COUNT(*) FROM hits WHERE Title <> '' AND POSITION('news' IN Title) > 0 GROUP BY BrowserCountry ORDER BY 2 DESC LIMIT 25;
SELECT REGEXP_REPLACE(SearchPhrase, '[0-9]+', 'N') AS k, COUNT(*) FROM hits WHERE SearchPhrase <> '' GROUP BY k ORDER BY 2 DESC LIMIT 25;
SELECT MobilePhone, MobilePhoneModel, COUNT(*) AS c, COUNT(DISTINCT UserID) AS u FROM hits WHERE MobilePhoneModel <> '' GROUP BY MobilePhone, MobilePhoneModel ORDER BY u DESC LIMIT 25;
SELECT UserAgentMinor, COUNT(*), COUNT(DISTINCT UserID) FROM hits WHERE UserAgentMinor <> '' GROUP BY UserAgentMinor ORDER BY 2 DESC LIMIT 25;
SELECT EventDate, COUNT(*), COUNT(DISTINCT UserID), AVG(LENGTH(URL)) FROM hits WHERE LENGTH(URL) > 100 GROUP BY EventDate ORDER BY EventDate;
SELECT LENGTH(URL) AS l, COUNT(*), COUNT(DISTINCT UserID) FROM hits WHERE URL <> '' GROUP BY l HAVING COUNT(*) > 100 ORDER BY 2 DESC LIMIT 25;
SELECT COUNT(*) FROM hits WHERE URL LIKE '%video%' OR URL LIKE '%movie%' OR URL LIKE '%film%';
SELECT RegionID, AVG(CASE WHEN AdvEngineID > 0 THEN 1.0 ELSE 0.0 END) AS adv_rate, COUNT(*) AS c, COUNT(DISTINCT UserID) AS u FROM hits GROUP BY RegionID HAVING COUNT(*) > 100000 ORDER BY adv_rate DESC LIMIT 25;
SELECT TraficSourceID, COUNT(*) FILTER (WHERE IsMobile = 1) AS m, COUNT(*) FILTER (WHERE IsMobile = 0) AS d, COUNT(DISTINCT UserID) AS u FROM hits GROUP BY TraficSourceID ORDER BY u DESC LIMIT 25;
SELECT RegionID, COUNT(DISTINCT UserID) FILTER (WHERE IsMobile = 1) AS m_users, COUNT(DISTINCT UserID) FILTER (WHERE IsMobile = 0) AS d_users FROM hits GROUP BY RegionID ORDER BY m_users + d_users DESC LIMIT 25;
SELECT CASE WHEN AdvEngineID = 0 AND SearchEngineID = 0 THEN 'organic' WHEN AdvEngineID > 0 THEN 'ad' ELSE 'search' END AS src, COUNT(*) AS c, COUNT(DISTINCT UserID) AS u FROM hits GROUP BY src ORDER BY c DESC;
SELECT EventDate, AVG(CASE WHEN IsRefresh = 1 THEN 1.0 ELSE 0.0 END) AS refresh_rate, AVG(CASE WHEN IsLink = 1 THEN 1.0 ELSE 0.0 END) AS link_rate, AVG(CASE WHEN IsDownload = 1 THEN 1.0 ELSE 0.0 END) AS dl_rate, COUNT(DISTINCT UserID) AS u FROM hits GROUP BY EventDate ORDER BY EventDate;
SELECT URL, COUNT(*) AS c, COUNT(DISTINCT UserID) AS u FROM hits WHERE URL <> '' GROUP BY URL HAVING COUNT(*) > 1000 ORDER BY c DESC LIMIT 25;
SELECT Title, COUNT(*) AS c, COUNT(DISTINCT UserID) AS u FROM hits WHERE Title <> '' GROUP BY Title HAVING COUNT(*) > 100 ORDER BY u DESC LIMIT 25;
SELECT URL, AVG(LENGTH(Title)) AS at, COUNT(*) AS c FROM hits WHERE URL <> '' AND Title <> '' GROUP BY URL HAVING COUNT(*) > 100 ORDER BY at DESC LIMIT 25;
SELECT RegionID, COUNT(DISTINCT URL) AS u, COUNT(*) AS c FROM hits WHERE URL <> '' GROUP BY RegionID HAVING COUNT(*) > 100000 ORDER BY u DESC LIMIT 25;
SELECT BrowserCountry, COUNT(DISTINCT BrowserLanguage) AS langs, COUNT(*) AS c FROM hits WHERE BrowserCountry <> '' GROUP BY BrowserCountry ORDER BY langs DESC LIMIT 25;
SELECT URL FROM hits WHERE URL LIKE '%news%' ORDER BY EventTime DESC LIMIT 25;
SELECT * FROM hits WHERE Title LIKE '%Google%' ORDER BY EventTime DESC LIMIT 10;
SELECT URL, EventTime FROM hits WHERE URL <> '' ORDER BY EventTime LIMIT 25 OFFSET 1000;
SELECT URL, COUNT(*) FROM hits WHERE EventDate BETWEEN '2013-07-01' AND '2013-07-15' AND URL <> '' GROUP BY URL ORDER BY 2 DESC LIMIT 25;
SELECT DISTINCT URL FROM hits WHERE URL LIKE '%news%' ORDER BY URL LIMIT 100;
SELECT DISTINCT BrowserCountry, BrowserLanguage FROM hits WHERE BrowserCountry <> '' ORDER BY BrowserCountry, BrowserLanguage LIMIT 100;
SELECT URLHash % 100 AS bucket, COUNT(*), COUNT(DISTINCT UserID) FROM hits GROUP BY bucket ORDER BY bucket;
SELECT MOD(WatchID, 100) AS bucket, COUNT(DISTINCT UserID) FROM hits GROUP BY bucket ORDER BY 2 DESC LIMIT 25;
SELECT OS, COUNT(DISTINCT URLHash) FROM hits GROUP BY OS ORDER BY 2 DESC LIMIT 25;
SELECT FLOOR(ClientIP / 16777216) AS class_a, COUNT(*), COUNT(DISTINCT UserID) FROM hits GROUP BY class_a ORDER BY 2 DESC LIMIT 25;
SELECT IPNetworkID, COUNT(*), COUNT(DISTINCT UserID) FROM hits GROUP BY IPNetworkID ORDER BY 2 DESC LIMIT 25;
SELECT FLOOR(LOG(GREATEST(ResolutionWidth, 1))) AS lw, COUNT(*), COUNT(DISTINCT UserID), AVG(ResolutionHeight) FROM hits GROUP BY lw ORDER BY lw;
SELECT * FROM (SELECT URL, COUNT(*) AS c, ROW_NUMBER() OVER (ORDER BY COUNT(*) DESC) AS rn FROM hits WHERE URL <> '' GROUP BY URL) t WHERE rn <= 25;
SELECT EventDate, COUNT(DISTINCT UserID) AS c, AVG(COUNT(DISTINCT UserID)) OVER (ORDER BY EventDate ROWS BETWEEN 2 PRECEDING AND CURRENT ROW) AS ma3 FROM hits GROUP BY EventDate ORDER BY EventDate;
SELECT OS, RegionID, COUNT(*) AS c, COUNT(*) * 1.0 / SUM(COUNT(*)) OVER (PARTITION BY OS) AS pct FROM hits GROUP BY OS, RegionID HAVING COUNT(*) > 10000 ORDER BY OS, c DESC;
SELECT EventDate, RegionID, COUNT(*) AS c, ROW_NUMBER() OVER (PARTITION BY EventDate ORDER BY COUNT(*) DESC) AS rn FROM hits GROUP BY EventDate, RegionID QUALIFY rn <= 5 ORDER BY EventDate, rn;
WITH heavy_users AS (SELECT UserID FROM hits GROUP BY UserID HAVING COUNT(*) > 100) SELECT COUNT(*) FROM heavy_users;
WITH cnt AS (SELECT URL, COUNT(*) AS c FROM hits WHERE URL <> '' GROUP BY URL) SELECT MIN(c), MAX(c), AVG(c), COUNT(*) FROM cnt WHERE c > 100;
WITH t AS (SELECT EventDate, COUNT(DISTINCT UserID) AS c FROM hits GROUP BY EventDate) SELECT EventDate, c, c - LAG(c) OVER (ORDER BY EventDate) AS diff FROM t ORDER BY EventDate;
SELECT COUNT(*) FROM hits WHERE UserID IN (SELECT UserID FROM hits WHERE SearchPhrase <> '' GROUP BY UserID HAVING COUNT(*) > 5);
SELECT URL, COUNT(*) FROM hits WHERE URL IN (SELECT URL FROM hits WHERE Title LIKE '%news%' GROUP BY URL HAVING COUNT(*) > 100) GROUP BY URL ORDER BY 2 DESC LIMIT 25;
SELECT 'mobile' AS type, COUNT(*) AS c, COUNT(DISTINCT UserID) AS u FROM hits WHERE IsMobile = 1 UNION ALL SELECT 'desktop', COUNT(*), COUNT(DISTINCT UserID) FROM hits WHERE IsMobile = 0;
SELECT a.RegionID, a.mob, a.mob_users, b.desk, b.desk_users FROM (SELECT RegionID, COUNT(*) AS mob, COUNT(DISTINCT UserID) AS mob_users FROM hits WHERE IsMobile = 1 GROUP BY RegionID) a JOIN (SELECT RegionID, COUNT(*) AS desk, COUNT(DISTINCT UserID) AS desk_users FROM hits WHERE IsMobile = 0 GROUP BY RegionID) b ON a.RegionID = b.RegionID ORDER BY a.mob + b.desk DESC LIMIT 25;
SELECT EventDate, COUNT(*), COUNT(DISTINCT UserID), COUNT(DISTINCT URL), COUNT(DISTINCT SearchPhrase) FROM hits GROUP BY EventDate ORDER BY EventDate;
SELECT REGEXP_REPLACE(URL, '^https?://(?:www\.)?([^/]+).*', '\1') AS host, COUNT(*) AS c, COUNT(DISTINCT UserID) AS u, AVG(LENGTH(URL)) AS al FROM hits WHERE URL <> '' GROUP BY host HAVING COUNT(*) > 10000 ORDER BY u DESC LIMIT 25;
SELECT EventDate, COUNT(*) FROM hits WHERE Title LIKE '%news%' OR Title LIKE '%sport%' GROUP BY EventDate ORDER BY EventDate;
SELECT URL, EventTime FROM hits WHERE URL LIKE '%shop%' OR URL LIKE '%cart%' ORDER BY EventTime DESC LIMIT 25;
SELECT BrowserCountry, BrowserLanguage, COUNT(*) AS c FROM hits WHERE BrowserCountry <> '' AND BrowserLanguage <> '' GROUP BY BrowserCountry, BrowserLanguage HAVING COUNT(*) > 1000 ORDER BY c DESC LIMIT 50;
SELECT REGEXP_REPLACE(SearchPhrase, '\s+', ' ') AS k, COUNT(*) AS c FROM hits WHERE SearchPhrase <> '' GROUP BY k ORDER BY c DESC LIMIT 25;
SELECT EXTRACT(HOUR FROM EventTime) AS h, EXTRACT(MINUTE FROM EventTime) AS m, COUNT(*), COUNT(DISTINCT UserID) FROM hits GROUP BY h, m ORDER BY 3 DESC LIMIT 25;
SELECT DATE_TRUNC('week', EventDate) AS week, COUNT(*), COUNT(DISTINCT UserID) FROM hits GROUP BY week ORDER BY week;
SELECT OS, AVG(SendTiming + DNSTiming + ConnectTiming + ResponseStartTiming + ResponseEndTiming) AS total_ms, COUNT(*) AS c, COUNT(DISTINCT UserID) AS u FROM hits WHERE SendTiming > 0 GROUP BY OS HAVING COUNT(*) > 10000 ORDER BY total_ms DESC LIMIT 25;
SELECT EventDate, AVG(LENGTH(URL)), AVG(LENGTH(Referer)), AVG(LENGTH(Title)), COUNT(DISTINCT UserID) FROM hits WHERE URL <> '' GROUP BY EventDate ORDER BY EventDate;
SELECT UserAgent, COUNT(*), COUNT(DISTINCT UserID), AVG(ResolutionWidth) FROM hits GROUP BY UserAgent ORDER BY 2 DESC LIMIT 25;
SELECT FlashMajor, FlashMinor, COUNT(*), COUNT(DISTINCT UserID) FROM hits WHERE FlashMajor > 0 GROUP BY FlashMajor, FlashMinor ORDER BY 3 DESC LIMIT 25;
SELECT ResolutionWidth, ResolutionHeight, COUNT(*), COUNT(DISTINCT UserID) FROM hits WHERE ResolutionWidth > 0 GROUP BY ResolutionWidth, ResolutionHeight ORDER BY 3 DESC LIMIT 25;
SELECT WindowClientWidth, WindowClientHeight, COUNT(*), COUNT(DISTINCT UserID) FROM hits WHERE WindowClientWidth > 0 AND WindowClientHeight > 0 GROUP BY WindowClientWidth, WindowClientHeight ORDER BY 3 DESC LIMIT 25;
SELECT URLRegionID, COUNT(*), COUNT(DISTINCT UserID), COUNT(DISTINCT URL) FROM hits WHERE URLRegionID <> 0 GROUP BY URLRegionID ORDER BY 2 DESC LIMIT 25;
SELECT MobilePhoneModel, COUNT(*) AS c, COUNT(DISTINCT UserID) AS u, AVG(ResolutionWidth) FROM hits WHERE MobilePhoneModel <> '' GROUP BY MobilePhoneModel ORDER BY u DESC LIMIT 25;
SELECT EventDate, COUNT(*) FILTER (WHERE Title LIKE '%news%') AS news, COUNT(*) FILTER (WHERE Title LIKE '%sport%') AS sport, COUNT(*) FILTER (WHERE Title LIKE '%video%') AS video FROM hits GROUP BY EventDate ORDER BY EventDate;
SELECT COUNT(*) FROM hits WHERE URL LIKE '%search%' AND SearchPhrase <> '';
SELECT SearchEngineID, COUNT(*), COUNT(DISTINCT SearchPhrase), COUNT(DISTINCT UserID) FROM hits WHERE SearchEngineID > 0 GROUP BY SearchEngineID ORDER BY 2 DESC LIMIT 25;
SELECT SearchPhrase, COUNT(*) AS c, COUNT(DISTINCT UserID) AS u, AVG(LENGTH(SearchPhrase)) AS al FROM hits WHERE SearchPhrase <> '' GROUP BY SearchPhrase HAVING COUNT(*) > 10 ORDER BY u DESC LIMIT 25;
SELECT REGEXP_REPLACE(Referer, '\\?.*', '') AS clean_ref, COUNT(*), COUNT(DISTINCT UserID) FROM hits WHERE Referer <> '' GROUP BY clean_ref ORDER BY 2 DESC LIMIT 25;
SELECT EventDate, MIN(EventTime), MAX(EventTime), COUNT(*), COUNT(DISTINCT UserID), COUNT(DISTINCT URL) FROM hits WHERE EventDate BETWEEN '2013-07-01' AND '2013-07-15' GROUP BY EventDate ORDER BY EventDate;
SELECT UTMSource, COUNT(*), COUNT(DISTINCT UserID), COUNT(DISTINCT URL), AVG(LENGTH(URL)) FROM hits GROUP BY UTMSource ORDER BY 2 DESC LIMIT 25;
SELECT FromTag, COUNT(*), COUNT(DISTINCT UserID), COUNT(DISTINCT URL) FROM hits WHERE FromTag <> '' GROUP BY FromTag ORDER BY 2 DESC LIMIT 25;
SELECT OpenstatServiceName, COUNT(*), COUNT(DISTINCT UserID), COUNT(DISTINCT URL), COUNT(DISTINCT Referer) FROM hits GROUP BY OpenstatServiceName ORDER BY 2 DESC LIMIT 25;
SELECT SocialSourceNetworkID, COUNT(*), COUNT(DISTINCT UserID), COUNT(DISTINCT URL), AVG(LENGTH(SocialSourcePage)) FROM hits GROUP BY SocialSourceNetworkID ORDER BY 2 DESC LIMIT 25;
SELECT PageCharset, COUNT(*), COUNT(DISTINCT UserID), COUNT(DISTINCT URL) FROM hits WHERE PageCharset <> '' GROUP BY PageCharset ORDER BY 2 DESC LIMIT 25;
SELECT EventDate, RegionID, COUNT(*), COUNT(DISTINCT UserID), AVG(ResolutionWidth) FROM hits WHERE EventDate BETWEEN '2013-07-08' AND '2013-07-15' GROUP BY EventDate, RegionID HAVING COUNT(*) > 1000 ORDER BY EventDate, 4 DESC LIMIT 100;
SELECT ParamCurrency, COUNT(*), AVG(ParamPrice), COUNT(DISTINCT UserID) FROM hits WHERE ParamCurrency <> '' GROUP BY ParamCurrency ORDER BY 2 DESC LIMIT 25;
SELECT COUNT(*) FROM hits WHERE URL LIKE '%.html%' AND Referer LIKE '%http%';
SELECT REGEXP_REPLACE(URL, '^https?://([^/]+)/([^/]*).*', '\1\2') AS prefix, COUNT(*) AS c FROM hits WHERE URL <> '' GROUP BY prefix HAVING COUNT(*) > 100 ORDER BY c DESC LIMIT 25;
SELECT EventDate, BrowserCountry, COUNT(*), COUNT(DISTINCT UserID) FROM hits WHERE BrowserCountry <> '' GROUP BY EventDate, BrowserCountry HAVING COUNT(*) > 1000 ORDER BY EventDate, 4 DESC LIMIT 100;
